import base64,os
FILES={
  'src/lib/uploadRules.ts': '',
  'prisma/schema.prisma': '',
  'src/app/api/projects/[id]/files/register/route.ts': '',
  'src/app/projects/[id]/page.tsx': '',
}
for rel,b64 in FILES.items():
    d=os.path.dirname(rel)
    if d: os.makedirs(d,exist_ok=True)
    open(rel,'wb').write(base64.b64decode(b64)); print('ecrit',rel)
print('')
print('=== Lot A applique. ETAPES SUIVANTES : ===')
print('  1) npx prisma db push   (ajoute la colonne upload_rules)')
print('  2) git add -A && git commit -m "feat(upload): regles par niveau" && git push')